#############################################################################
### statistics of window data
m4c_m5c_sliding_windows_combine_summary <- m6a_m4c_m5c_sliding_windows_combine %>%
  group_by(modified_base_code, phase, genus) %>%
  summarise(mean_fraction_modified = mean(fraction_modified),
            sd_fraction_modified = sd(fraction_modified), 
            mean_modified_number=mean(sum_modified_number), 
            sd_modified_number=sd(sum_modified_number), .groups = "drop")

fraction_modified_windows_compare <- m6a_m4c_m5c_sliding_windows_combine %>%
  group_by(modified_base_code, genus) %>%
  t_test(data = ., fraction_modified ~ phase, paired = T) %>%
  add_significance() %>%
  add_xy_position(x="modified_base_code", dodge = 0.8)

fraction_modified_windows_modified_base_compare <- m6a_m4c_m5c_sliding_windows_combine %>%
  group_by(genus) %>%
  t_test(data = ., fraction_modified ~ modified_base_code, paired = F) %>%
  adjust_pvalue() %>%
  add_significance() %>%
  add_xy_position(x="modified_base_code")
  

fraction_modified_windows_modified_base_phase_compare <- m6a_m4c_m5c_sliding_windows_combine %>%
  group_by(genus, phase) %>%
  t_test(data = ., fraction_modified ~ modified_base_code, paired = F) %>%
  adjust_pvalue() %>%
  add_significance() %>%
  add_xy_position(x="modified_base_code")
  
