## ecoli
ggplot(m6a_m4c_m5c_sliding_windows_combine[m6a_m4c_m5c_sliding_windows_combine$genus=="Escherichia",], aes(x=modified_base_code,y=fraction_modified)) +
  geom_boxplot(aes(fill=phase), alpha=0.8) +
  scale_fill_manual("Phase", breaks=c("exponential", "stationary"),
                    values = c("#444574", "#cd534cff")) +
  scale_y_continuous(limits = c(0, NA),
                     breaks = c(0, 1, 4, 10, 30),
                     labels = c(0, 1, 4, 10, 30)) +
  stat_pvalue_manual(fraction_modified_windows_compare[fraction_modified_windows_compare$genus=="Escherichia",], hide.ns = TRUE,
                     label = "{p.signif}", size=9, bracket.size=1) +
  stat_pvalue_manual(fraction_modified_windows_modified_base_compare[fraction_modified_windows_modified_base_compare$genus=="Escherichia",], hide.ns = TRUE,
                     label = "{p.adj.signif}", size=9, bracket.size=1) +
  coord_trans(y="log1p") +
  labs(y="Modified fraction (%)") +
  theme_bw() +
  theme(axis.title.x = element_blank(),
        axis.title.y = element_text(face = "bold"),
        legend.title = element_text(face = "bold")) +
  theme(text = element_text(size = 24),
        axis.title.x = element_blank(),
        legend.position = "bottom",
        strip.background = element_blank())

