### examine the dna methylation variation around oriC and ter
m6a_m4c_m5c_sliding_windows_combine_chrom <- m6a_m4c_m5c_sliding_windows_combine[m6a_m4c_m5c_sliding_windows_combine$chrom=="NC_002695.2" | m6a_m4c_m5c_sliding_windows_combine$chrom=="NZ_CP139575.1",]
ecoli_ter_middle <- (2115426+2115454)/2
lacidophilus_ter_middle <- 759661

ecoli_origin_middle <- (4719203+4179580)/2

lacidophilus_origin_1_middle <- (1644596+1645071)/2
lacidophilus_origin_2_middle <- (1646440+1646616)/2

m6a_m4c_m5c_sliding_windows_combine_chrom$replicate <- sub("_exp|_sta", "", m6a_m4c_m5c_sliding_windows_combine_chrom$replicate)

m6a_m4c_m5c_sliding_windows_combine_chrom$replicate <- factor(m6a_m4c_m5c_sliding_windows_combine_chrom$replicate)

m6a_m4c_m5c_sliding_windows_combine_chrom <- as.data.frame(m6a_m4c_m5c_sliding_windows_combine_chrom)

m6a_m4c_m5c_sliding_windows_combine_chrom_fraction_wider <- m6a_m4c_m5c_sliding_windows_combine_chrom %>%
  select(-sum_valid_coverage, -sum_modified_number) %>%
  pivot_wider(names_from = phase, values_from = fraction_modified) %>%
  mutate(differential_fraction_modified=(stationary+1)/(exponential+1),
         log2_differential_fraction_modified=log2((stationary+1)/(exponential+1)))


m6a_m4c_m5c_sliding_windows_combine_chrom_fraction_wider_summary <- m6a_m4c_m5c_sliding_windows_combine_chrom_fraction_wider %>%
  group_by(genus, modified_base_code, chrom, start, end) %>%
  summarize(mean_differential_fraction_modified = mean(log2(differential_fraction_modified)), 
            sd_differential_fraction_modified = sd(log2(differential_fraction_modified)), 
            mean_log2_differential_fraction_modified=mean(log2_differential_fraction_modified), 
            sd_log2_differential_fraction_modified=sd(log2_differential_fraction_modified), .groups = "drop") %>%
  mutate(rel_position_ter=ifelse(genus=="Escherichia", ((start+end)/2)-ecoli_ter_middle, ((start+end)/2)-lacidophilus_ter_middle),
         rel_position_origin_1=ifelse(genus=="Escherichia", ((start+end)/2)-ecoli_origin_middle, ((start+end)/2)-lacidophilus_origin_1_middle),
         rel_position_origin_2=ifelse(genus=="Escherichia", ((start+end)/2)-ecoli_origin_middle, ((start+end)/2)-lacidophilus_origin_2_middle),
         position_middle=(start+end)/2) %>%
  mutate(direction_ter=ifelse(rel_position_ter>=0, "upstream", "downstream"),
         direction_rel_position_origin_1=ifelse(rel_position_origin_1>=0, "upstream", "downstream"),
         direction_rel_position_origin_2=ifelse(rel_position_origin_2>=0, "upstream", "downstream"))

